#include <algorithm>

void adaptive_sort(std::vector<int>& arr) {
    size_t n = arr.size();
    if (n < 2) return;
    int* b = arr.data();
    int* e = b + n;
    int* p = b;

    while (++p < e && *p == *(p - 1));
    if (p == e) return;

    if (*p > *(p - 1)) {
        while (++p < e && *p >= *(p - 1));
        if (p == e) return;
    } else {
        while (++p < e && *p <= *(p - 1));
        if (p == e) { std::reverse(b, e); return; }
    }

    std::sort(b, e);
}

